-- 99 Asmaul Husna — the standard published enumeration (the famous
-- Tirmidhi listing, as printed in Kemenag RI material and mushaf
-- appendices across Indonesia), as a new Amalan Harian group so it gets
-- the existing Arabic + latin + meaning + narration treatment for free.
-- Item 1 is the authenticating hadith (Bukhari & Muslim); items 2-100 are
-- the names themselves in order.

INSERT OR IGNORE INTO amalan_category (slug, grp, name_id, name_ar, icon, sort_order) VALUES ('asmaul-husna', 'asmaul', '99 Asmaul Husna', 'الأسماء الحسنى', '🌟', 100);
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('asmaul-husna', 1, 'Keutamaan Asmaul Husna', 'إِنَّ لِلَّهِ تِسْعَةً وَتِسْعِينَ اسْمًا مِائَةً إِلَّا وَاحِدًا مَنْ أَحْصَاهَا دَخَلَ الْجَنَّةَ', 'Inna lillaahi tis''atan wa tis''iina isman, mi''atan illaa waahidan, man ahshaahaa dakhalal-jannah', 'Sesungguhnya Allah memiliki sembilan puluh sembilan nama, seratus kurang satu; barang siapa menghafalnya (menjaganya), ia masuk surga.', 'Menghafal di sini mencakup memahami maknanya dan hidup dengannya — bukan sekadar melafalkan.', NULL, 'HR. Bukhari & Muslim');
